def _pprint_estimator(self, object, stream, indent, allowance, context,
                      level):
    stream.write(object.__class__.__name__ + '(')
    if self._indent_at_name:
        indent += len(object.__class__.__name__)

    if self._changed_only:
        params = _changed_params(object)
    else:
        params = object.get_params(deep=False)

    params = OrderedDict((name, val)
                         for (name, val) in sorted(params.items()))

    self._format_params(params.items(), stream, indent, allowance + 1,
                        context, level)
    stream.write(')')

def _format_dict_items(self, items, stream, indent, allowance, context,
                       level):
    return self._format_params_or_dict_items(
        items, stream, indent, allowance, context, level, is_dict=True)

def _collect_probas(self, X):
    """Collect results from clf.predict calls. """
    return np.asarray([clf.predict_proba(X) for clf in self.estimators_])

def _replace_estimator(self, attr, name, new_val):
    # assumes `name` is a valid estimator name
    new_estimators = list(getattr(self, attr))
    for i, (estimator_name, _) in enumerate(new_estimators):
        if estimator_name == name:
            new_estimators[i] = (name, new_val)
            break
    setattr(self, attr, new_estimators)

def _check_solver(solver, penalty, dual):
    all_solvers = ['liblinear', 'newton-cg', 'lbfgs', 'sag', 'saga']
    if solver not in all_solvers:
        raise ValueError("Logistic Regression supports only solvers in %s, got"
                         " %s." % (all_solvers, solver))

    all_penalties = ['l1', 'l2', 'elasticnet', 'none']
    if penalty not in all_penalties:
        raise ValueError("Logistic Regression supports only penalties in %s,"
                         " got %s." % (all_penalties, penalty))

    if solver not in ['liblinear', 'saga'] and penalty not in ('l2', 'none'):
        raise ValueError("Solver %s supports only 'l2' or 'none' penalties, "
                         "got %s penalty." % (solver, penalty))
    if solver != 'liblinear' and dual:
        raise ValueError("Solver %s supports only "
                         "dual=False, got dual=%s" % (solver, dual))

    if penalty == 'elasticnet' and solver != 'saga':
        raise ValueError("Only 'saga' solver supports elasticnet penalty,"
                         " got solver={}.".format(solver))

    if solver == 'liblinear' and penalty == 'none':
        raise ValueError(
            "penalty='none' is not supported for the liblinear solver"
        )

    return solver

def _check_multi_class(multi_class, solver, n_classes):
    if multi_class == 'auto':
        if solver == 'liblinear':
            multi_class = 'ovr'
        elif n_classes > 2:
            multi_class = 'multinomial'
        else:
            multi_class = 'ovr'
    if multi_class not in ('multinomial', 'ovr'):
        raise ValueError("multi_class should be 'multinomial', 'ovr' or "
                         "'auto'. Got %s." % multi_class)
    if multi_class == 'multinomial' and solver == 'liblinear':
        raise ValueError("Solver %s does not support "
                         "a multinomial backend." % solver)
    return multi_class

def _initialize(self, X, y, init):
    """Initialize the transformation.

    Parameters
    ----------
    X : array-like, shape (n_samples, n_features)
        The training samples.

    y : array-like, shape (n_samples,)
        The training labels.

    init : string or numpy array of shape (n_features_a, n_features_b)
        The validated initialization of the linear transformation.

    Returns
    -------
    transformation : array, shape (n_components, n_features)
        The initialized linear transformation.

    """

    transformation = init
    if self.warm_start and hasattr(self, 'components_'):
        transformation = self.components_
    elif isinstance(init, np.ndarray):
        pass
    else:
        n_samples, n_features = X.shape
        n_components = self.n_components or n_features
        if init == 'auto':
            n_classes = len(np.unique(y))
            if n_components <= min(n_features, n_classes - 1):
                init = 'lda'
            elif n_components < min(n_features, n_samples):
                init = 'pca'
            else:
                init = 'identity'
        if init == 'identity':
            transformation = np.eye(n_components, X.shape[1])
        elif init == 'random':
            transformation = self.random_state_.randn(n_components,
                                                      X.shape[1])
        elif init in {'pca', 'lda'}:
            init_time = time.time()
            if init == 'pca':
                pca = PCA(n_components=n_components,
                          random_state=self.random_state_)
                if self.verbose:
                    print('Finding principal components... ', end='')
                    sys.stdout.flush()
                pca.fit(X)
                transformation = pca.components_
            elif init == 'lda':
                from ..discriminant_analysis import (
                    LinearDiscriminantAnalysis)
                lda = LinearDiscriminantAnalysis(n_components=n_components)
                if self.verbose:
                    print('Finding most discriminative components... ',
                          end='')
                    sys.stdout.flush()
                lda.fit(X, y)
                transformation = lda.scalings_.T[:n_components]
            if self.verbose:
                print('done in {:5.2f}s'.format(time.time() - init_time))
    return transformation

def _check_param_grid(param_grid):
    if hasattr(param_grid, 'items'):
        param_grid = [param_grid]

    for p in param_grid:
        for name, v in p.items():
            if isinstance(v, np.ndarray) and v.ndim > 1:
                raise ValueError("Parameter array should be one-dimensional.")

            if (isinstance(v, str) or
                    not isinstance(v, (np.ndarray, Sequence))):
                raise ValueError("Parameter values for parameter ({0}) need "
                                 "to be a sequence(but not a string) or"
                                 " np.ndarray.".format(name))

            if len(v) == 0:
                raise ValueError("Parameter values for parameter ({0}) need "
                                 "to be a non-empty sequence.".format(name))

def _compute_kernel(self, X):
    """Return the data transformed by a callable kernel"""
    if callable(self.kernel):
        # in the case of precomputed kernel given as a function, we
        # have to compute explicitly the kernel matrix
        kernel = self.kernel(X, self.__Xfit)
        if sp.issparse(kernel):
            kernel = kernel.toarray()
        X = np.asarray(kernel, dtype=np.float64, order='C')
    return X

def _validate_for_predict(self, X):
    check_is_fitted(self)

    X = check_array(X, accept_sparse='csr', dtype=np.float64, order="C",
                    accept_large_sparse=False)
    if self._sparse and not sp.isspmatrix(X):
        X = sp.csr_matrix(X)
    if self._sparse:
        X.sort_indices()

    if sp.issparse(X) and not self._sparse and not callable(self.kernel):
        raise ValueError(
            "cannot use sparse input in %r trained on dense data"
            % type(self).__name__)
    n_samples, n_features = X.shape

    if self.kernel == "precomputed":
        if X.shape[1] != self.shape_fit_[0]:
            raise ValueError("X.shape[1] = %d should be equal to %d, "
                             "the number of samples at training time" %
                             (X.shape[1], self.shape_fit_[0]))
    elif n_features != self.shape_fit_[1]:
        raise ValueError("X.shape[1] = %d should be equal to %d, "
                         "the number of features at training time" %
                         (n_features, self.shape_fit_[1]))
    return X

def _equal_similarities_and_preferences(S, preference):
    def all_equal_preferences():
        return np.all(preference == preference.flat[0])

    def all_equal_similarities():
        # Create mask to ignore diagonal of S
        mask = np.ones(S.shape, dtype=bool)
        np.fill_diagonal(mask, 0)

        return np.all(S[mask].flat == S[mask].flat[0])

    return all_equal_preferences() and all_equal_similarities()

def all_equal_similarities():
    # Create mask to ignore diagonal of S
    mask = np.ones(S.shape, dtype=bool)
    np.fill_diagonal(mask, 0)

    return np.all(S[mask].flat == S[mask].flat[0])

def _num_samples(x):
    """Return number of samples in array-like x."""
    message = 'Expected sequence or array-like, got %s' % type(x)
    if hasattr(x, 'fit') and callable(x.fit):
        # Don't get num_samples from an ensembles length!
        raise TypeError(message)

    if not hasattr(x, '__len__') and not hasattr(x, 'shape'):
        if hasattr(x, '__array__'):
            x = np.asarray(x)
        else:
            raise TypeError(message)

    if hasattr(x, 'shape') and x.shape is not None:
        if len(x.shape) == 0:
            raise TypeError("Singleton array %r cannot be considered"
                            " a valid collection." % x)
        # Check that shape is returning an integer or default to len
        # Dask dataframes may not return numeric shape[0] value
        if isinstance(x.shape[0], numbers.Integral):
            return x.shape[0]

    try:
        return len(x)
    except TypeError:
        raise TypeError(message)

def _auto_wrap_is_configured(estimator):
    """Return True if estimator is configured for auto-wrapping the transform method.

    `_SetOutputMixin` sets `_sklearn_auto_wrap_output_keys` to `set()` if auto wrapping
    is manually disabled.
    """
    auto_wrap_output_keys = getattr(estimator, "_sklearn_auto_wrap_output_keys", set())
    return (
        hasattr(estimator, "get_feature_names_out")
        and "transform" in auto_wrap_output_keys
    )

def _hstack(self, Xs):
    """Stacks Xs horizontally.

    This allows subclasses to control the stacking behavior, while reusing
    everything else from ColumnTransformer.

    Parameters
    ----------
    Xs : list of {array-like, sparse matrix, dataframe}
    """
    if self.sparse_output_:
        try:
            # since all columns should be numeric before stacking them
            # in a sparse matrix, `check_array` is used for the
            # dtype conversion if necessary.
            converted_Xs = [
                check_array(X, accept_sparse=True, force_all_finite=False)
                for X in Xs
            ]
        except ValueError as e:
            raise ValueError(
                "For a sparse output, all columns should "
                "be a numeric or convertible to a numeric."
            ) from e

        return sparse.hstack(converted_Xs).tocsr()
    else:
        Xs = [f.toarray() if sparse.issparse(f) else f for f in Xs]
        config = _get_output_config("transform", self)
        if config["dense"] == "pandas" and all(hasattr(X, "iloc") for X in Xs):
            pd = check_pandas_support("transform")
            output = pd.concat(Xs, axis=1)

            # If all transformers define `get_feature_names_out`, then transform
            # will adjust the column names to be consistent with
            # verbose_feature_names_out. Here we prefix the feature names if
            # verbose_feature_names_out=True.

            if not self.verbose_feature_names_out:
                return output

            transformer_names = [
                t[0] for t in self._iter(fitted=True, replace_strings=True)
            ]
            feature_names_outs = [X.columns for X in Xs]
            names_out = self._add_prefix_for_feature_names_out(
                list(zip(transformer_names, feature_names_outs))
            )
            output.columns = names_out
            return output

        return np.hstack(Xs)

def _add_prefix_for_feature_names_out(self, transformer_with_feature_names_out):
    """Add prefix for feature names out that includes the transformer names.

    Parameters
    ----------
    transformer_with_feature_names_out : list of tuples of (str, array-like of str)
        The tuple consistent of the transformer's name and its feature names out.

    Returns
    -------
    feature_names_out : ndarray of shape (n_features,), dtype=str
        Transformed feature names.
    """
    if self.verbose_feature_names_out:
        # Prefix the feature names out with the transformers name
        names = list(
            chain.from_iterable(
                (f"{name}__{i}" for i in feature_names_out)
                for name, feature_names_out in transformer_with_feature_names_out
            )
        )
        return np.asarray(names, dtype=object)

    # verbose_feature_names_out is False
    # Check that names are all unique without a prefix
    feature_names_count = Counter(
        chain.from_iterable(s for _, s in transformer_with_feature_names_out)
    )
    top_6_overlap = [
        name for name, count in feature_names_count.most_common(6) if count > 1
    ]
    top_6_overlap.sort()
    if top_6_overlap:
        if len(top_6_overlap) == 6:
            # There are more than 5 overlapping names, we only show the 5
            # of the feature names
            names_repr = str(top_6_overlap[:5])[:-1] + ", ...]"
        else:
            names_repr = str(top_6_overlap)
        raise ValueError(
            f"Output feature names: {names_repr} are not unique. Please set "
            "verbose_feature_names_out=True to add prefixes to feature names"
        )

    return np.concatenate(
        [name for _, name in transformer_with_feature_names_out],
    )

def _iter(self, fitted=False, replace_strings=False, column_as_strings=False):
    """
    Generate (name, trans, column, weight) tuples.

    If fitted=True, use the fitted transformers, else use the
    user specified transformers updated with converted column names
    and potentially appended with transformer for remainder.

    """
    if fitted:
        if replace_strings:
            # Replace "passthrough" with the fitted version in
            # _name_to_fitted_passthrough
            def replace_passthrough(name, trans, columns):
                if name not in self._name_to_fitted_passthrough:
                    return name, trans, columns
                return name, self._name_to_fitted_passthrough[name], columns

            transformers = [
                replace_passthrough(*trans) for trans in self.transformers_
            ]
        else:
            transformers = self.transformers_
    else:
        # interleave the validated column specifiers
        transformers = [
            (name, trans, column)
            for (name, trans, _), column in zip(self.transformers, self._columns)
        ]
        # add transformer tuple for remainder
        if self._remainder[2]:
            transformers = chain(transformers, [self._remainder])
    get_weight = (self.transformer_weights or {}).get

    output_config = _get_output_config("transform", self)
    for name, trans, columns in transformers:
        if replace_strings:
            # replace 'passthrough' with identity transformer and
            # skip in case of 'drop'
            if trans == "passthrough":
                trans = FunctionTransformer(
                    accept_sparse=True,
                    check_inverse=False,
                    feature_names_out="one-to-one",
                ).set_output(transform=output_config["dense"])
            elif trans == "drop":
                continue
            elif _is_empty_column_selection(columns):
                continue

        if column_as_strings:
            # Convert all columns to using their string labels
            columns_is_scalar = np.isscalar(columns)

            indices = self._transformer_to_input_indices[name]
            columns = self.feature_names_in_[indices]

            if columns_is_scalar:
                # selection is done with one dimension
                columns = columns[0]

        yield (name, trans, columns, get_weight(name))

def _validate_transformers(self):
    if not self.transformers:
        return

    names, transformers, _ = zip(*self.transformers)

    # validate names
    self._validate_names(names)

    # validate estimators
    for t in transformers:
        if t in ("drop", "passthrough"):
            continue
        if not (hasattr(t, "fit") or hasattr(t, "fit_transform")) or not hasattr(
            t, "transform"
        ):
            # Used to validate the transformers in the `transformers` list
            raise TypeError(
                "All estimators should implement fit and "
                "transform, or can be 'drop' or 'passthrough' "
                "specifiers. '%s' (type %s) doesn't." % (t, type(t))
            )

def _validate_column_callables(self, X):
    """
    Converts callable column specifications.
    """
    all_columns = []
    transformer_to_input_indices = {}
    for name, _, columns in self.transformers:
        if callable(columns):
            columns = columns(X)
        all_columns.append(columns)
        transformer_to_input_indices[name] = _get_column_indices(X, columns)

    self._columns = all_columns
    self._transformer_to_input_indices = transformer_to_input_indices

def _validate_output(self, result):
    """
    Ensure that the output of each transformer is 2D. Otherwise
    hstack can raise an error or produce incorrect results.
    """
    names = [
        name for name, _, _, _ in self._iter(fitted=True, replace_strings=True)
    ]
    for Xs, name in zip(result, names):
        if not getattr(Xs, "ndim", 0) == 2:
            raise ValueError(
                "The output of the '{0}' transformer should be 2D (scipy "
                "matrix, array, or pandas DataFrame).".format(name)
            )

def _record_output_indices(self, Xs):
    """
    Record which transformer produced which column.
    """
    idx = 0
    self.output_indices_ = {}

    for transformer_idx, (name, _, _, _) in enumerate(
        self._iter(fitted=True, replace_strings=True)
    ):
        n_columns = Xs[transformer_idx].shape[1]
        self.output_indices_[name] = slice(idx, idx + n_columns)
        idx += n_columns

    # `_iter` only generates transformers that have a non empty
    # selection. Here we set empty slices for transformers that
    # generate no output, which are safe for indexing
    all_names = [t[0] for t in self.transformers] + ["remainder"]
    for name in all_names:
        if name not in self.output_indices_:
            self.output_indices_[name] = slice(0, 0)

def _pandas_dtype_needs_early_conversion(pd_dtype):
    """Return True if pandas extension pd_dtype need to be converted early."""
    # Check these early for pandas versions without extension dtypes
    from pandas.api.types import (
        is_bool_dtype,
        is_sparse,
        is_float_dtype,
        is_integer_dtype,
    )

    if is_bool_dtype(pd_dtype):
        # bool and extension booleans need early converstion because __array__
        # converts mixed dtype dataframes into object dtypes
        return True

    if is_sparse(pd_dtype):
        # Sparse arrays will be converted later in `check_array`
        return False

    try:
        from pandas.api.types import is_extension_array_dtype
    except ImportError:
        return False

    if is_sparse(pd_dtype) or not is_extension_array_dtype(pd_dtype):
        # Sparse arrays will be converted later in `check_array`
        # Only handle extension arrays for integer and floats
        return False
    elif is_float_dtype(pd_dtype):
        # Float ndarrays can normally support nans. They need to be converted
        # first to map pd.NA to np.nan
        return True
    elif is_integer_dtype(pd_dtype):
        # XXX: Warn when converting from a high integer to a float
        return True

    return False

